fn map_to_hilbert_space(x: f32, y: f32) -> f32 {
let mut x = x;
let mut y = y;
let mut z = 0.0;
let mut w = 1.0;

while (x >= 0.0 && x < 1.0) && (y >= 0.0 && y < 1.0) {
    z += w;
    x = x * 2 + 1;
    y = y * 2 + 1;
    w = w * 2;
}

z /= 4.0;
w /= 4.0;

return z + (x - (z + y)) * w;
}

