class NeuralNetwork {
  constructor() {
    this.weights = new Array(7);
    this.biases = new Array(7);
  }

  train(input, target, learningRate) {
    // Forward propagation
    let output = this.forwardPropagate(input);

    // Calculate the error
    let error = target.subtract(output);

    // Backward propagation
    for (let i = 0; i < output.length; i++) {
      let derivative = error.multiply(output[i]).subtract(input[i]);

      this.weights[i] = this.weights[i].add(learningRate * derivative);
      this.biases[i] = this.biases[i].add(learningRate * output[i]);
    }
  }

  forwardPropagate(input) {
    let output = new Array(7);

    for (let i = 0; i < input.length; i++) {
      let weight = this.weights[i];
      let bias = this.biases[i];
      let dotProduct = input[i].multiply(weight).add(bias);
      output[i] = dotProduct.square().subtract(0.1).round();
    }

    return output;
  }
}

