Here is a simple implementation of a neural network with backpropagation using ES6 JavaScript:

```javascript
class NeuralNetwork {
  constructor(inputNodes, hiddenNodes, outputNodes, learningRate) {
    this.inputNodes = inputNodes;
    this.hiddenNodes = hiddenNodes;
    this.outputNodes = outputNodes;
    this.learningRate = learningRate;

    this.weights_ih = new Matrix(this.hiddenNodes, this.inputNodes).randomize();
    this.weights_ho = new Matrix(this.outputNodes, this.hiddenNodes).randomize();

    this.bias_h = new Matrix(this.hiddenNodes, 1).randomize();
    this.bias_o = new Matrix(this.outputNodes, 1).randomize();
  }

  sigmoid(x) {
    return 1 / (1 + Math.exp(-x));
  }

  sigmoidDerivative(x) {
    return x * (1 - x);
  }

  train(inputArray, targetArray) {
    // Forward pass
    let inputs = Matrix.fromArray(inputArray);
    let hidden = Matrix.multiply(this.weights_ih, inputs);
    hidden.add(this.bias_h);
    hidden.map(this.sigmoid);

    let outputs = Matrix.multiply(this.weights_ho, hidden);
    outputs.add(this.bias_o);
    outputs.map(this.sigmoid);

    // Calculate output errors
    let targets = Matrix.fromArray(targetArray);
    let outputErrors = Matrix.subtract(targets, outputs);

    // Calculate hidden errors
    let weights_ho_transpose = Matrix.transpose(this.weights_ho);
    let hiddenErrors = Matrix.multiply(weights_ho_transpose, outputErrors);

    // Backpropagation
    let gradients = Matrix.map(outputs, this.sigmoidDerivative);
    gradients.multiply(outputErrors);
    gradients.multiply(this.learningRate);

    let hidden_T = Matrix.transpose(hidden);
    let weights_ho_delta = Matrix.multiply(gradients, hidden_T);
    this.weights_ho.add(weights_ho_delta);
    this.bias_o.add(gradients);

    let hidden_gradients = Matrix.map(hidden, this.sigmoidDerivative);
    hidden_gradients.multiply(hiddenErrors);
    hidden_gradients.multiply(this.learningRate);

    let inputs_T = Matrix.transpose(inputs);
    let weights_ih_delta = Matrix.multiply(hidden_gradients, inputs_T);
    this.weights_ih.add(weights_ih_delta);
    this.bias_h.add(hidden_gradients);
  }

  predict(inputArray) {
    let inputs = Matrix.fromArray(inputArray);
    let hidden = Matrix.multiply(this.weights_ih, inputs);
    hidden.add(this.bias_h);
    hidden.map(this.sigmoid);

    let outputs = Matrix.multiply(this.weights_ho, hidden);
    outputs.add(this.bias_o);
    outputs.map(this.sigmoid);

    return outputs.toArray();
  }
}
```

This code assumes the existence of a Matrix class with basic matrix operations (add, subtract, multiply, map, etc.). You can find a simple Matrix class implementation in this GitHub repository: https://github.com/CodingTrain/Toy-Neural-Network-JS/blob/master/lib/matrix.js

